82	async fn main() -> Result<(), rocket::Error> {
83	    dotenvy::dotenv().ok();
84	
85	    // ── Config ────────────────────────────────────────────────────────────────
86	    let app_config = AppConfig::from_env().unwrap_or_else(|e| {
87	        eprintln!("FATAL configuration error: {e}");
88	        std::process::exit(1);
89	    });
90	
91	    // ── Structured logging ────────────────────────────────────────────────────
92	    tracing_subscriber::registry()
93	        .with(EnvFilter::new(&app_config.log_level))
94	        .with(fmt::layer().json().flatten_event(true))
95	        .init();
96	
97	    // ── Crypto key validation ─────────────────────────────────────────────────
98	    let cipher = Cipher::from_base64_key(&app_config.encryption_key).unwrap_or_else(|e| {
99	        tracing::error!(
100	            error = %e,
101	            "FATAL: encryption key validation failed. \
102	            The ENCRYPTION_KEY environment variable is missing or invalid. \
103	            You must generate a 32-byte Base64-encoded key and set it in your .env file as: \
104	            ENCRYPTION_KEY=\"<base64-encoded-32-byte-key>\". \
105	            To generate one, run: \
106	            openssl rand -base64 32 \
107	            or (Python): python3 -c \"import secrets, base64; print(base64.b64encode(secrets.token_bytes(32)).decode())\"",
108	        );
109	        std::process::exit(1);
110	    });
111	
112	    // ── Database ──────────────────────────────────────────────────────────────
113	    let conn = db::connect(&app_config).await.unwrap_or_else(|e| {
114	        tracing::error!(
115	            error = %e,
116	            "FATAL: database connection failed. \
117	            Check that DATABASE_URL in your .env file points to a valid SQLite path \
118	            and that the target directory (e.g. data/) exists and is writable by this process. \
119	            You can create the directory with: mkdir -p data && chmod 755 data",
120	        );
121	        std::process::exit(1);
122	    });
123	
124	    // ── Seed roles ────────────────────────────────────────────────────────────
125	    rbac::seeder::seed_roles(&conn).await.unwrap_or_else(|e| {
126	        tracing::error!(error = %e, "FATAL: role seeding failed");
127	        std::process::exit(1);
128	    });
129	
130	    // ── Seed default users ────────────────────────────────────────────────────
131	    auth::seeder::seed_users(&conn).await.unwrap_or_else(|e| {
132	        tracing::error!(error = %e, "FATAL: user seeding failed");
133	        std::process::exit(1);
134	    });
135	
136	    // ── Nightly backup scheduler ──────────────────────────────────────────────
137	    {
138	        use std::path::PathBuf;
139	        use std::sync::Arc;
140	        backup::scheduler::start(
141	            Arc::new(conn.clone()),
142	            PathBuf::from(&app_config.backup_dir),
143	            app_config.backup_retain_days,
144	        );
145	    }
146	
147	    tracing::info!(
148	        version   = env!("CARGO_PKG_VERSION"),
149	        host      = %app_config.host,
150	        port      = app_config.port,
151	        log_level = %app_config.log_level,
152	        "motorsport-backend starting",
153	    );
154	
155	    // ── Rocket ────────────────────────────────────────────────────────────────
156	    let rocket_cfg = rocket::Config {
157	        address: app_config
158	            .host
159	            .parse()
160	            .unwrap_or_else(|_| "0.0.0.0".parse().unwrap()),
161	        port: app_config.port,
162	        log_level: rocket::config::LogLevel::Off,
163	        ..rocket::Config::default()
164	    };
165	
166	    rocket::custom(rocket_cfg)
167	        .attach(CorrelationFairing)
168	        .attach(RequestLoggerFairing)
169	        .manage(app_config)
170	        .manage(cipher)
171	        .manage(conn)
172	        .mount("/", routes![health, login, logout, rotate_password])
173	        .mount("/", routes![assign_role, revoke_role, list_user_roles])
174	        .mount(
