176	            routes![
177	                create_event,
178	                get_event,
179	                list_events,
180	                update_event,
181	                publish_event,
182	                create_ruleset,
183	                get_ruleset,
184	                list_rulesets,
185	                rollback_ruleset,
186	            ],
187	        )
188	        .mount("/", routes![submit_result, get_rankings, export_results])
189	        .mount(
190	            "/",
191	            routes![
192	                create_vehicle,
193	                get_vehicle,
194	                list_vehicles,
195	                update_vehicle,
196	                transition_status,
197	                get_vehicle_history,
198	            ],
199	        )
200	        .mount(
201	            "/",
202	            routes![
203	                create_asset,
204	                get_asset,
205	                list_assets,
206	                update_asset,
207	                update_status,
208	                get_history,
209	                export_assets,
