13	/// Open the SQLite connection pool and run all pending migrations.
14	///
15	/// Before opening any connections this function checks whether a restore was
16	/// staged by a previous run (via `POST /admin/backups/<filename>/restore`).
17	/// If a `.restore_pending` marker is found the backup is copied over the live
18	/// database file and the marker is deleted — restoring the database to the
19	/// backed-up state before any application code touches it.
20	///
21	/// Connection options are tuned for a single-node SQLite deployment:
22	/// - WAL journal mode is enabled by default by sqlx-sqlite.
23	/// - Connection pool is sized conservatively (1–5) since SQLite serialises writes.
24	/// - Performance PRAGMAs are applied immediately after the pool opens.
25	pub async fn connect(config: &AppConfig) -> Result<DatabaseConnection, sea_orm::DbErr> {
26	    // ── Ensure database directory and file exist ───────────────────────────────
27	    // sqlx/SQLite does not create the database file automatically; the
28	    // directory must also exist when running on a fresh volume mount.
29	    if let Some(db_file) = backup_service::db_path_from_url(&config.database_url) {
30	        if let Some(parent) = db_file.parent() {
31	            std::fs::create_dir_all(parent).map_err(|e| {
32	                sea_orm::DbErr::Custom(format!("Cannot create database directory: {e}"))
33	            })?;
34	        }
35	        if !db_file.exists() {
36	            std::fs::File::create(&db_file).map_err(|e| {
37	                sea_orm::DbErr::Custom(format!("Cannot initialise database file: {e}"))
38	            })?;
39	        }
40	    }
41	
42	    // ── Pending restore check ─────────────────────────────────────────────────
43	    let backup_dir = PathBuf::from(&config.backup_dir);
44	    if let Some(db_file) = backup_service::db_path_from_url(&config.database_url) {
45	        match backup_service::apply_pending_restore(&backup_dir, &db_file) {
46	            Ok(true) => {
47	                tracing::info!(
48	                    db_file = %db_file.display(),
49	                    "database.restore_applied — proceeding with restored database"
50	                );
51	            }
52	            Ok(false) => {} // No restore pending — normal startup.
53	            Err(e) => {
54	                // A failed restore is fatal: we do not know if the database
55	                // file is in a consistent state.
56	                return Err(sea_orm::DbErr::Custom(format!(
57	                    "Staged restore failed at startup: {e}"
58	                )));
59	            }
60	        }
61	    }
62	
63	    // ── Connection pool ───────────────────────────────────────────────────────
64	    let mut opts = ConnectOptions::new(&config.database_url);
65	    opts.max_connections(5)
66	        .min_connections(1)
67	        .connect_timeout(Duration::from_secs(5))
68	        .acquire_timeout(Duration::from_secs(5))
69	        .idle_timeout(Duration::from_secs(300))
70	        .sqlx_logging(false); // query-level logging handled by our tracing layer
71	
72	    let conn = Database::connect(opts).await?;
73	
74	    tracing::info!(url = %config.database_url, "database.connecting");
75	
76	    // ── SQLite performance PRAGMAs ────────────────────────────────────────────
77	    // Applied once after the pool opens; effective for every subsequent
78	    // connection acquired from the pool via the per-connection PRAGMA hook.
79	    //
80	    // synchronous = NORMAL — skips the full-fsync on every commit while still
81	    //   providing crash-safe writes in WAL mode.  Dramatically reduces latency
82	    //   on spinning disks and networked volumes.
83	    //
84	    // cache_size = -64000 — 64 MiB page cache (negative = kibibytes).  Keeps
85	    //   hot pages in memory and avoids repeat reads for the primary hot tables
86	    //   (invoices, payments, audit_log, vehicles).
87	    //
88	    // temp_store = MEMORY — stores temporary B-trees and sort buffers in RAM
89	    //   rather than on disk.  Benefits the analytics queries and ranking
90	    //   computations that sort large intermediate result sets.
91	    //
92	    // mmap_size = 268435456 — 256 MiB memory-mapped I/O window.  Sequential
93	    //   scans (data-quality checks, audit log queries) avoid read() system
94	    //   calls; pages are faulted directly into the process address space.
95	    //
96	    // busy_timeout = 5000 — wait up to 5 s before returning SQLITE_BUSY when
97	    //   a writer holds the WAL write lock.  Prevents spurious 500 errors under
98	    //   brief write contention.
99	    for pragma in &[
100	        "PRAGMA journal_mode = WAL",
101	        "PRAGMA synchronous = NORMAL",
102	        "PRAGMA cache_size = -64000",
103	        "PRAGMA temp_store = MEMORY",
104	        "PRAGMA mmap_size = 268435456",
105	        "PRAGMA busy_timeout = 5000",
106	    ] {
107	        conn.execute(Statement::from_string(
108	            DbBackend::Sqlite,
109	            pragma.to_string(),
110	        ))
111	        .await?;
112	    }
113	
114	    tracing::info!("database.pragmas_applied");
115	
116	    // ── Migrations ────────────────────────────────────────────────────────────
117	    Migrator::up(&conn, None).await?;
118	
119	    tracing::info!("database.migrations_applied");
120	
121	    Ok(conn)
122	}
